using System.Collections.Generic;
using System.Globalization;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Input;
using Quicker.Public; // ICustomWindowContext

static Window _win;
static IDictionary<string, object> _dataContext;
static ICustomWindowContext _winContext;

static string _displayText = "0";
static string _expressionText = "";
static string _pendingOperator = "";
static double _leftValue = 0;
static bool _isNewInput = true;
static bool _hasLeftValue = false;

// OnWindowCreated 必须存在
public static void OnWindowCreated(Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    _win = win;
    _dataContext = dataContext;
    _winContext = winContext;

    ClearState();
    UpdateView("示例：OnButtonClicked / FindName绑定 / RunSpAsync / 快捷键");
}

// 可选：访问已加载控件、绑定事件，此时窗口句柄已可用
public static void OnWindowLoaded(Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    Button clearButton = _win.FindName("BtnClear") as Button;
    clearButton.Click += OnClearButtonClick;

    _win.KeyDown += OnWindowKeyDown;
}

// 普通按钮点击回调：大部分按钮通过 Tag 分发
public static bool OnButtonClicked(string controlName, object controlTag, Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    string tag = Convert.ToString(controlTag, CultureInfo.InvariantCulture);

    if (tag == "back")
    {
        Backspace();
        return true;
    }

    if (tag == "dot")
    {
        AppendDot();
        return true;
    }

    if (tag == "sign")
    {
        ToggleSign();
        return true;
    }

    if (tag == "percent")
    {
        PercentCurrent();
        return true;
    }

    if (tag == "equal")
    {
        Evaluate();
        return true;
    }

    if (tag == "copy")
    {
        CopyResult();
        return true;
    }

    if (tag == "send")
    {
        SendResultToSubProgram();
        return true;
    }

    if (tag == "close")
    {
        _win.Close();
        return true;
    }

    if (tag.StartsWith("digit:", StringComparison.Ordinal))
    {
        AppendDigit(tag.Substring(6));
        return true;
    }

    if (tag.StartsWith("op:", StringComparison.Ordinal))
    {
        SetOperator(tag.Substring(3));
        return true;
    }

    return true;
}

// 示例：这个按钮不走 OnButtonClicked，而是在 OnWindowLoaded 中 FindName 后手动绑定
static void OnClearButtonClick(object sender, RoutedEventArgs e)
{
    ClearState();
    UpdateView("已清空：AC 按钮来自 OnWindowLoaded + FindName 手动绑定");
}

// 示例：键盘快捷键
static void OnWindowKeyDown(object sender, KeyEventArgs e)
{
    if (e.Key == Key.Escape)
    {
        _win.Close();
        e.Handled = true;
        return;
    }

    if (e.Key == Key.Enter || e.Key == Key.Return)
    {
        Evaluate();
        e.Handled = true;
        return;
    }
}

static void ClearState()
{
    _displayText = "0";
    _expressionText = "";
    _pendingOperator = "";
    _leftValue = 0;
    _isNewInput = true;
    _hasLeftValue = false;
}

static void AppendDigit(string digit)
{
    if (_isNewInput)
    {
        _displayText = digit;
        _isNewInput = false;
    }
    else if (_displayText == "0")
    {
        _displayText = digit;
    }
    else if (_displayText == "-0")
    {
        _displayText = "-" + digit;
    }
    else
    {
        _displayText = _displayText + digit;
    }

    UpdateView("输入数字");
}

static void AppendDot()
{
    if (_isNewInput)
    {
        _displayText = "0.";
        _isNewInput = false;
    }
    else if (_displayText.IndexOf(".", StringComparison.Ordinal) < 0)
    {
        _displayText = _displayText + ".";
    }

    UpdateView("输入小数");
}

static void Backspace()
{
    if (_isNewInput)
    {
        UpdateView("当前没有可退格的输入");
        return;
    }

    if (_displayText.Length <= 1)
    {
        _displayText = "0";
        _isNewInput = true;
    }
    else if (_displayText.Length == 2 && _displayText.StartsWith("-", StringComparison.Ordinal))
    {
        _displayText = "0";
        _isNewInput = true;
    }
    else
    {
        _displayText = _displayText.Substring(0, _displayText.Length - 1);
    }

    UpdateView("已退格");
}

static void ToggleSign()
{
    if (_displayText == "0")
    {
        _displayText = "-0";
        _isNewInput = false;
    }
    else if (_displayText.StartsWith("-", StringComparison.Ordinal))
    {
        _displayText = _displayText.Substring(1);
    }
    else
    {
        _displayText = "-" + _displayText;
    }

    UpdateView("切换正负号");
}

static void PercentCurrent()
{
    double value;

    if (!TryGetDisplayValue(out value))
    {
        ShowError("当前数字无效");
        return;
    }

    value = value / 100.0;
    _displayText = FormatNumber(value);
    _isNewInput = true;

    UpdateView("百分号：当前数字 ÷ 100");
}

static void SetOperator(string op)
{
    double currentValue;

    if (!TryGetDisplayValue(out currentValue))
    {
        ShowError("当前数字无效");
        return;
    }

    if (_hasLeftValue && !_isNewInput)
    {
        double tempResult;

        if (!TryCalculate(_leftValue, currentValue, _pendingOperator, out tempResult))
            return;

        _leftValue = tempResult;
        _displayText = FormatNumber(tempResult);
    }
    else
    {
        _leftValue = currentValue;
        _hasLeftValue = true;
    }

    _pendingOperator = op;
    _expressionText = FormatNumber(_leftValue) + " " + ToDisplayOperator(op);
    _isNewInput = true;

    UpdateView("已选择运算符");
}

static void Evaluate()
{
    if (!_hasLeftValue || _pendingOperator.Length == 0)
    {
        UpdateView("没有待计算的表达式");
        return;
    }

    double rightValue;

    if (!TryGetDisplayValue(out rightValue))
    {
        ShowError("当前数字无效");
        return;
    }

    double result;

    if (!TryCalculate(_leftValue, rightValue, _pendingOperator, out result))
        return;

    _expressionText = FormatNumber(_leftValue) + " " + ToDisplayOperator(_pendingOperator) + " " + FormatNumber(rightValue) + " =";
    _displayText = FormatNumber(result);

    _leftValue = result;
    _pendingOperator = "";
    _hasLeftValue = false;
    _isNewInput = true;

    UpdateView("计算完成");
}

static bool TryCalculate(double left, double right, string op, out double result)
{
    result = 0;

    if (op == "+")
    {
        result = left + right;
        return true;
    }

    if (op == "-")
    {
        result = left - right;
        return true;
    }

    if (op == "*")
    {
        result = left * right;
        return true;
    }

    if (op == "/")
    {
        if (Math.Abs(right) < 0.000000000001)
        {
            ShowError("不能除以 0");
            return false;
        }

        result = left / right;
        return true;
    }

    ShowError("未知运算符");
    return false;
}

static void CopyResult()
{
    try
    {
        Clipboard.SetText(_displayText);
        UpdateView("结果已复制到剪贴板");
    }
    catch
    {
        UpdateView("复制失败：剪贴板暂不可用");
    }
}

static void SendResultToSubProgram()
{
    Dictionary<string, object> args = new Dictionary<string, object>();
    args["text"] = _displayText;
    args["expression"] = _expressionText;

    _winContext.RunSpAsync("ShowCalcResult", args);

    UpdateView("已调用子程序 ShowCalcResult，传入 text 和 expression");
}

static void ShowError(string message)
{
    ClearState();
    _displayText = "错误";
    _isNewInput = true;
    UpdateView(message);
}

static bool TryGetDisplayValue(out double value)
{
    string text = _displayText;

    if (text == "-0")
        text = "0";

    return double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out value);
}

static string FormatNumber(double value)
{
    if (Math.Abs(value) < 0.000000000001)
        value = 0;

    return value.ToString("0.############", CultureInfo.InvariantCulture);
}

static string ToDisplayOperator(string op)
{
    if (op == "*")
        return "×";

    if (op == "/")
        return "÷";

    return op;
}

static void UpdateView(string statusText)
{
    _dataContext["DisplayText"] = _displayText;
